mapper.select:
SELECT a.*, u.nickname as author_name, u.avatar as author_avatar,
       c.name as category_name
FROM article a
LEFT JOIN user u ON a.author_id = u.id
LEFT JOIN category c ON a.category_id = c.id

    AND a.status = #{status}
    AND a.review_status = #{reviewStatus}
    AND a.category_id = #{categoryId}
    AND a.author_id = #{authorId}

        AND a.id IN (SELECT article_id FROM article_tag WHERE tag_id = #{tagId})


        AND (a.title LIKE CONCAT('%',#{keyword},'%')
             OR a.summary LIKE CONCAT('%',#{keyword},'%'))


ORDER BY a.is_top DESC, a.created_at DESC
